-- Verify: count updated rows and check stats
SELECT
  COUNT(*) FILTER (WHERE hrc_historical_reference IS NOT NULL) AS rows_with_historical,
  ROUND(AVG(hrc_historical_reference)::numeric, 3) AS avg_hrc_historical,
  ROUND(AVG(hrc_score - hrc_historical_reference)::numeric, 3) AS avg_change_since_baseline
FROM hrc_tiles
WHERE longitude BETWEEN 89.6 AND 96.2
  AND latitude BETWEEN 24.0 AND 28.3;
